import React, { useEffect } from "react";
import NestLogo from "../components/NestLogo";

export default function SplashScreen({ onFinish }) {
  useEffect(() => {
    const timer = setTimeout(() => {
      onFinish(); // move to SignIn or Dashboard
    }, 2500);
    return () => clearTimeout(timer);
  }, [onFinish]);

  return (
    <div className="w-screen h-screen flex flex-col items-center justify-center bg-gradient-to-br from-emerald-600 to-teal-800 text-white">
      <NestLogo size="text-6xl" />
      <h1 className="mt-6 text-3xl font-bold">Nest App</h1>
      <p className="mt-2 text-sm opacity-70">Smart Finance at your Fingertips</p>
    </div>
  );
}
